1	interface Item {
2	  type: string;
3	}
4	
5	interface QuoteStep {
6	  op: "quote";
7	  items: Item[];
8	}
9	
10	type Step = QuoteStep;
11	
12	interface Scenario {
13	  customer: { yearsWithMHPCO: number };
14	  steps: Step[];
15	}
16	
17	const BASE_PREMIUM: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	  rune: 25,
23	};
24	
25	const FIRST_INSURANCE_NUMERATOR = 11;
26	const FIRST_INSURANCE_DENOMINATOR = 10;
27	const PROCESSING_FEE = 5;
28	
29	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
30	  const results = scenario.steps.map((step) => {
31	    const base = step.items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
32	    const withFirstInsurance =
33	      (base * FIRST_INSURANCE_NUMERATOR) / FIRST_INSURANCE_DENOMINATOR;
34	    const premium = Math.ceil(withFirstInsurance + PROCESSING_FEE);
35	    return { premium };
36	  });
37	  return { results };
38	};
